#!/usr/bin/env python3
"""
Aplica el modulo de Resenas/Retroalimentacion de MagicBee.
Ejecutar desde la raiz del repo (carpeta que contiene 'src'):
    python3 apply_reviews_feature.py

Escribe/sobrescribe estos archivos con su version final:
  - src/app/api/reviews/route.ts
  - src/app/dashboard/reviews/page.tsx
  - src/app/p/[slug]/cita/[id]/page.tsx
  - src/app/p/[slug]/page.tsx
  - src/components/AppointmentsClient.tsx
  - src/components/CitaManageClient.tsx
  - src/components/ClientsClient.tsx
  - src/components/DashboardClient.tsx
  - src/components/PortalClient.tsx
  - src/components/ReviewsClient.tsx
  - src/components/SchedulesClient.tsx
  - src/components/ServicesClient.tsx
  - src/components/SettingsClient.tsx
  - src/components/StaffClient.tsx
  - src/components/StatsClient.tsx
  - src/components/cita-manage.css
  - src/components/portal.css
  - src/components/reviews.css
"""

import base64
from pathlib import Path

FILES = {
    'src/app/api/reviews/route.ts': """""",
    'src/app/dashboard/reviews/page.tsx': """""",
    'src/app/p/[slug]/cita/[id]/page.tsx': """""",
    'src/app/p/[slug]/page.tsx': """""",
    'src/components/AppointmentsClient.tsx': """""",
    'src/components/CitaManageClient.tsx': """""",
    'src/components/ClientsClient.tsx': """""",
    'src/components/DashboardClient.tsx': """""",
    'src/components/PortalClient.tsx': """""",
    'src/components/ReviewsClient.tsx': """""",
    'src/components/SchedulesClient.tsx': """""",
    'src/components/ServicesClient.tsx': """""",
    'src/components/SettingsClient.tsx': """""",
    'src/components/StaffClient.tsx': """""",
    'src/components/StatsClient.tsx': """""",
    'src/components/cita-manage.css': """""",
    'src/components/portal.css': """""",
    'src/components/reviews.css': """""",
}

def main():
    for relpath, b64 in FILES.items():
        p = Path(relpath)
        p.parent.mkdir(parents=True, exist_ok=True)
        content = base64.b64decode(b64)
        p.write_bytes(content)
        print(f"escrito: {relpath} ({len(content)} bytes)")
    print()
    print("Listo. Revisa con 'git status', luego:")
    print("  git add -A")
    print("  git commit -m 'Modulo de resenas'")
    print("  git push")

if __name__ == "__main__":
    main()